<?php session_start(); if($_SESSION['id'] > 0){    require_once ('./../../../classes/mysql.class.php');    $db = new MySQL();    if($_GET['id_customer'] AND !empty($_GET['id_customer']) AND is_numeric($_GET['id_customer'])) //Un client séléctionné    {        $id_customer = $db->SQLfix($_GET['id_customer']);        $db->QUERY('SELECT COUNT(*) AS nb FROM clients WHERE id ="'.$id_customer.'"  AND compte_principal="'.$_SESSION['compte_principal'].'" ');        $row = $db->Row();        if($row->nb) //client existant        {                        $db->QUERY('SELECT c.nom, c.prenom, c.adresse, c.cp, c.ville, c.fixe, c.portable, c.mail, (SELECT clients.nom AS nom_ent FROM clients WHERE clients.id = c.id_parent) AS nom_ent                        FROM clients AS c                         WHERE id="'.$id_customer.'"  AND compte_principal="'.$_SESSION['compte_principal'].'" ');            $row = $db->Row();                        $filename = $row->nom;            if(!empty($row->prenom))                $filename .= '_'.$row->prenom;            header('Content-Type: text/plain');            header('Content-Disposition: attachment; filename="'.$filename.'.vcf"');                        ?>BEGIN:VCARD<?php echo "\n";?>VERSION:3.0<?php echo "\n";?>N:<?php echo utf8_decode($row->prenom);?>;<?php echo utf8_decode($row->nom);?><?php echo "\n";?>FN:<?php echo utf8_decode($row->nom);?> <?php echo utf8_decode($row->prenom);?><?php echo "\n";?>TEL;TYPE=WORK,VOICE:<?php echo $row->fixe;?><?php echo "\n";?>TEL;TYPE=CELL,VOICE:<?php echo $row->portable;?><?php echo "\n";?>ADR;TYPE=WORK:;;<?php echo utf8_decode($row->adresse);?>;<?php echo utf8_decode($row->ville);?>;;<?php echo $row->cp;?>;<?php echo "\n";?>LABEL;TYPE=WORK:<?php echo utf8_decode($row->adresse);?> <?php echo $row->cp;?> <?php echo utf8_decode($row->ville);?><?php echo "\n";?>EMAIL;TYPE=PREF,INTERNET:<?php echo $row->mail;?><?php echo "\n";?><?php if(!empty($row->nom_ent))    echo 'ORG:'.utf8_decode ($row->nom_ent);?><?php echo "\n";?>END:VCARD<?php                                            }    }}?>